INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-SPM-001', 'Schema Design and Data Modeling', 'AI assistance to design normalized relational schema for contract sheet system (entities, keys, relationships, indexes)', 'EPCS', 'Design', 'Design', 'Data Modeling', 'GitHub Copilot', '16H', '8', '8', 'Faster schema design and fewer review cycles; improves data quality and reduces rework', 'Provide business entities, attributes, and relationships; AI drafts ERD and table definitions; DBA reviews and adjusts for Oracle/APEX constraints.', 'AI accelerates first draft; human review ensures platform fit', '1) Pilot on one HLD/LLD or process-design package with architect-approved patterns.\n2) Measure draft-preparation time, correction rate, and review-cycle reduction.\n3) Reuse only approved templates, diagram rules, and prompt packs.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed Shaheen', 'Implemented', '6', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-SPM-002', 'Architecture Documentation', 'AI assistance designing  a structured business model and data architecture for managing project milestones, revenues, costs, and actuals with the specific requirements', 'EPCS', 'Analysis', 'Requirements Analysis', 'Architecture Documentation', 'GitHub Copilot', '24H', '16', '8', 'Standardized architecture docs; reduces analysis effort and speeds approval', 'Provide requirements; AI generates entity model and documentation; architect reviews and simplifies.', 'Improves consistency and speeds documentation', '1) Start with one approved artifact set and a fixed output template.\n2) Pilot on a single project/workshop and measure time saved plus review corrections.\n3) Promote validated prompt packs and review checklist into the BA knowledge base.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed Shaheen', 'Implemented', '7', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-SPM-004', 'Error Debugging and Handling', 'AI assistance in analyzing error messages and provide detailed explanations when encountering complex errors in APEX applications', 'EPCS', 'Development', 'Backend-Frontend', 'Debugging', 'GitHub Copilot', '2H', '0.5', '1.5', 'Reduces debugging time and improves developer productivity', 'Capture error message and code context; AI suggests root cause and fix; developer validates in non-prod before applying.', 'AI improves speed; validation still required', '1) Pilot on a bounded engineering task in a controlled repository.\n2) Enforce human review, unit/integration tests, and security checks on all AI-generated output.\n3) Package the winning prompt/context pattern as a reusable accelerator.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed Shaheen', 'Implemented', '~20', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EAS-BFSI-BA-01', 'BRD to User Stories Auto-Generation', 'AI converts BRD/SOW documents into structured epics, user stories, and acceptance criteria for LOS, LMS, SME, Mortgage and Cards projects.', 'BFSI', 'Analysis', 'Requirements Engineering', 'User Story Generation', 'Microsoft Copilot', '8-10 MD per project', '3-4 MD per project', '3', '40-60% documentation effort reduction and improved traceability.', 'Upload BRD/SOW; AI generates structured backlog aligned with templates.', 'Standardizes requirement quality across BFSI tower.', '1) Upload BRD/SOW (sanitized). 2) Provide BFSI context prompt (domain: LOS/Mortgage, regulatory constraints, acceptance criteria standards). 3) AI generates: epics, user stories, acceptance criteria, dependency notes. 4) BA Lead reviews against regulatory requirements. 5) Approved stories enter JIRA/ADO backlog. 6) Pilot: one LOS or Mortgage project BRD. 7) KPI: MD reduction per project; story quality score from delivery team.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Strong BFSI BA accelerator. AI converts BRD/SOW into epics, user stories, and acceptance criteria for LOS/LMS/SME/Mortgage/Cards. Effort from 8–10 MD to 3–4 MD (40–60% reduction). Named owner (BA Lead – BFSI), tool confirmed (Copilot). No blocking gaps.', 'High feasibility. BRD-to-user-story conversion is well-proven. Financial domain specificity (LOS, Mortgage) requires BFSI-aware prompt context. Risk: AI-generated acceptance criteria may miss regulatory and compliance constraints specific to banking. Mitigation: BFSI BA lead reviews all generated stories against regulatory requirements before backlog entry.', 'BA Lead - BFSI', 'Planned', 'All lending projects', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EAS-BFSI-SA-01', 'HLD/LLD Auto Drafting', 'AI generates architecture diagrams, integration flows, sequence diagrams and NFR checklist from BRD and integration inputs.', 'BFSI', 'Design', 'Architecture', 'HLD/LLD Generation', 'Microsoft Copilot', '12-15 MD', '6-8 MD', '3', '30-50% faster design cycle and reduced architecture review iterations.', 'Provide structured requirements and integration inventory.', 'Improves governance and architectural consistency.', '1) Provide BRD and integration inventory (systems, APIs, data flows). 2) AI generates: HLD diagram, integration blueprint, sequence diagrams, NFR checklist. 3) Solution Architect reviews against banking environment constraints. 4) Architecture Review Board sign-off. 5) Baseline approved artifacts. 6) Pilot: one integration-heavy BFSI program. 7) KPI: design cycle time before vs after; review iterations needed.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Strong architecture design accelerator. AI generates architecture diagrams, integration flows, sequence diagrams, and NFR checklists from BRD and integration inputs. Effort from 12–15 MD to 6–8 MD (30–50% reduction). Named owner (Solution Architecture Lead), tool confirmed (Copilot). Pilot: one integration-heavy BFSI program.', 'High feasibility for diagram and documentation drafting. Risk: AI may propose inappropriate patterns for regulated banking environments. Mitigation: mandatory Architecture Review Board sign-off on all AI-generated architecture before baselining.', 'Solution Architecture Lead', 'Planned', 'All integration-heavy programs', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EAS-BFSI-DM-01', 'Delivery Margin & Resource Optimization Engine', 'AI analyzes rate cards, MD allocation, and burn rate to predict margin impact and recommend resource optimization across towers.', 'BFSI', 'Monitoring & Control', 'Delivery Excellence', 'Cost & Margin Optimization', 'Microsoft Copilot', 'Manual financial analysis per project', 'Automated predictive margin modeling', '2', '5-8% margin improvement and 10-15% resource optimization.', 'Integrate PAS sheets and costing catalogues.', 'Protects profitability while improving delivery efficiency.', '1) Integrate PAS sheets and costing catalogues as AI input. 2) AI analyzes: rate card vs allocation, burn rate trends, margin variance per project. 3) AI generates: margin impact forecast, over/under-allocation flags, optimization recommendations. 4) Delivery Management Head reviews recommendations. 5) Approved actions implemented. 6) Pilot: 2–3 accounts. 7) KPI: margin % improvement; resource utilization before vs after.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Strong delivery excellence use case. AI analyzes rate cards, MD allocation, and burn rate to predict margin impact and recommend resource optimization. Outcome: 5–8% margin improvement, 10–15% resource optimization. Named owner (Delivery Management Head), tool confirmed (Copilot). Pilot: 2–3 accounts. No blocking gaps.', 'High feasibility for margin modeling and optimization recommendations. Risk: AI recommendations may not account for contractual constraints or client-relationship implications of resource changes. Mitigation: Delivery Management Head reviews and approves all resource optimization actions before execution.', 'Delivery Management Head', 'Planned', 'Strategic BFSI accounts (ARB, Banking clients)', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-ECM-003', 'AI-Assisted Excel Validation & CSV Conversion Tool', 'A Windows desktop application built using Python and Tkinter with AI assistance (GitHub Copilot) to validate, transform, and convert Excel data into structured CSV files with configurable business rules.', 'EPCS', 'Development', 'Process Automation', 'Data Validation & Transformation', 'GitHub Copilot', '24H', '8H', '16', 'Reduces manual data validation effort, minimizes human errors, improves data quality, accelerates data migration processes, and ensures consistency across datasets.', 'Prepare Excel input with defined structure, configure validation rules (manually or via Excel/JSON), run validation, review errors, and export valid data to CSV.', 'AI significantly accelerates development of internal tools, especially for data-heavy processes, and enables rapid prototyping with high-quality output.', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed Shaheen', 'Implemented', '3', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-001', 'Create Qualification Questions', 'You can use Generative AI to suggest questions on topics such as sustainability, governance, financial viability, and various supplier risks.', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Procurement', 'Oracle Fusion AI capabilities', '4', '1', '3', 'Reduces qualification question creation time and improves supplier evaluation consistency', 'Activate AI qualification feature in Oracle Fusion Procurement tenant; procurement lead reviews and approves generated questions.', 'Built-in Oracle AI feature; minimal setup required for activation', '1) Restrict first use to read-only analysis, recommendations, or dry-run output.\n2) Validate in non-production and document approval gates before operational use.\n3) Convert proven outputs into governed templates/runbooks rather than free-form prompting.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-002', 'Discover New Suppliers', 'Use generative Artificial Intelligence (AI) to discover suppliers who may or may not be currently registered but possess the capability to provide goods and services for your business. If you like a recommendation, you can register the supplier and invite them to participate in the negotiation.', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Procurement', 'Oracle Fusion AI capabilities', '8', '2', '6', 'Accelerates supplier discovery and broadens sourcing options', 'Activate Supplier Discovery AI in Oracle Fusion Procurement; configure search criteria and compliance filters.', 'Built-in Oracle AI feature; enables efficient supplier sourcing', '1) Pilot on one framework/domain with approved evidence sources and reviewer workflow.\n2) Measure preparation effort, review corrections, and audit-readiness quality.\n3) Release only reviewed outputs and preserve traceability to source controls/evidence.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-003', 'The Supplier Negotiation Details Agent', 'The Negotiation Status Advisor agent provides users with real-time access to the status and details of their supplier negotiations directly through an AI chat interface, without requiring involvement from the procurement team or buyers.', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Procurement', 'Oracle Fusion AI capabilities', '3', '1', '2', 'Reduces procurement team query workload and enables real-time negotiation visibility', 'Activate Negotiation Status Advisor in Oracle Fusion Procurement; configure data access scope and user permissions.', 'Built-in Oracle AI agent; improves self-service for negotiation tracking', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-004', 'The Procurement Policy Advisor Agent', 'Provides users with seamless access to procurement policies, allowing them to ask questions about products and services while ordering what they need to get their jobs done.', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Procurement', 'Oracle Fusion AI capabilities', '4', '1', '3', 'Improves procurement policy compliance and reduces policy-related support queries', 'Activate Procurement Policy Advisor in Oracle Fusion; upload and structure procurement policy documents into knowledge base.', 'Built-in Oracle AI agent; supports self-service procurement policy guidance', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-005', 'Leave and Absence Analyst - AI Agent', 'The Leave and Absence Analyst is an AI-powered digital assistant that helps you manage all aspects of your time off easily, accurately, and securely\n- Whether you''re checking your PTO balance, scheduling time off, donating leave to a colleague, or cashing out unused hours, this agent offers real-time support and guidance\n- Built on Oracles AI Agent framework and powered by large language models (LLMs), the agent understands your natural language queries and responds with accurate, secure information based on your role and privileges', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'HCM', 'Oracle Fusion AI capabilities', '3', '1', '2', 'Reduces HR leave-query ticket volume and improves employee self-service', 'Activate Leave and Absence Analyst agent in Oracle HCM Fusion; configure role-based data access; validate leave balance accuracy.', 'Built-in Oracle HCM AI agent; enables employee self-service for time-off management', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-006', 'Pay Analyst - AI Agent', 'The Pay Analyst is your AI-powered digital assistant for payroll, designed to make payslip access and payroll history transparent and easy for every employee\n- This digital worker enables you to review payslips, analyze key earnings and deductions, and clarify pay-related questionsâall through a secure, conversational interface\n- Built on Oracles AI Agent framework and powered by advanced large language models (LLMs), the agent interprets your natural language questions and delivers accurate, role-based information within your security permissions', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'HCM', 'Oracle Fusion AI capabilities', '3', '1', '2', 'Reduces payroll helpdesk ticket volume and improves employee pay transparency', 'Activate Pay Analyst agent in Oracle HCM Fusion; confirm PDPL-aligned data access controls; pilot with HR and Finance before full rollout.', 'Built-in Oracle HCM AI agent; improves employee self-service for payroll queries', '1) Pilot on one HLD/LLD or process-design package with architect-approved patterns.\n2) Measure draft-preparation time, correction rate, and review-cycle reduction.\n3) Reuse only approved templates, diagram rules, and prompt packs.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-007', 'Best Candidates AI Ranking', 'Recruiters can use the Best Candidates feature to review the recommended best candidates for open job requisitions\n- When the feature is enabled, you can see the Top Recommendations section in job requisitions\n- Candidates are sorted in order of recommendations, and you can refine the list of recommended candidates to review or decide who to invite to apply for a job', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Recruiting', 'Oracle Fusion AI capabilities', '6', '2', '4', 'Accelerates candidate shortlisting and reduces recruiter screening effort', 'Activate Best Candidates AI in Oracle Recruiting Cloud; HR defines diversity criteria; AI ranking is advisory, not final.', 'Built-in Oracle Recruiting AI feature; supports data-driven candidate evaluation', '1) Restrict first use to read-only analysis, recommendations, or dry-run output.\n2) Validate in non-production and document approval gates before operational use.\n3) Convert proven outputs into governed templates/runbooks rather than free-form prompting.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-008', 'Candidate Assistant Q&A', 'You can now answer candidate questions regarding job requisitions or the company using Oracle’s AI Assist, which is powered by Generative AI\n- As a recruiter, all you need to do is define information about the job requisition or company using the features available in Recruiting, and AI Assist will retrieve the answers from these sources and display the response in an engaging and conversational manner\n- This feature is an enhancement over the job- and company-related question intents that were previously used to answer candidate questions', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Recruiting', 'Oracle Fusion AI capabilities', '4', '1', '3', 'Improves candidate experience and reduces recruiter query handling time', 'Activate Oracle AI Assist in Recruiting Cloud; recruiters populate job requisition and company Q&A content; define content maintenance cadence.', 'Built-in Oracle Recruiting AI feature; enhances candidate engagement', '1) Restrict first use to read-only analysis, recommendations, or dry-run output.\n2) Validate in non-production and document approval gates before operational use.\n3) Convert proven outputs into governed templates/runbooks rather than free-form prompting.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-009', 'AI Agent for Job Skills Enrichment', 'Enrich job profiles with AI-suggested skills using a new AI agent called Job Skills Enrichment\n- This agent analyzes the job description, job title, skills associated with the job profile, your organization’s skills library, and other relevant HCM transactional data, and suggests new or additional skills that are relevant to the job profile\n- Note: These skill suggestions are added as ‘pending’ (also known as uncurated)', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'HCM', 'Oracle Fusion AI capabilities', '4', '1', '3', 'Enriches job profiles with relevant skills and reduces manual skills curation effort', 'Activate Job Skills Enrichment agent in Oracle HCM; define minimum data quality thresholds; HR reviews AI-suggested skills before approval.', 'Built-in Oracle HCM AI agent; supports skills-based talent management', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-010', 'AI Assistance Enhancements For Manager Evaluations In Redwood Performance  Documents', 'Leverage Artificial Intelligence (AI) assistance for manager evaluations in Redwood performance documents\n- with these enhancements: Enable managers to generate development tips for competencies based on manager entered comments, proficiencies, and ratings in addition to the competency name and description\n- Provide feedback to managers if there''s insufficient data to generate an overall summary comment to reduce misleading responses', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'HCM', 'Oracle Fusion AI capabilities', '4', '1', '3', 'Accelerates manager evaluation process and improves development tip quality', 'Activate AI Assistance in Redwood Performance Documents; define minimum data quality thresholds for AI generation to trigger.', 'Built-in Oracle Performance AI feature; supports competency-based development', '1) Pilot on one application/API scope with approved requirements and expected results.\n2) Track coverage improvement, preparation effort, and escaped defects.\n3) Reuse validated scenarios/prompts inside the QE repository.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-011', 'Intelligent Account Combination Defaulting for Invoices', 'AI-driven feature in Oracle Fusion Cloud Payables that automates the prediction and population of account code combination (distribution) segment value', 'ERP Solutions', 'Analysis / Activation', 'Platform AI Feature', 'Payables', 'Oracle Fusion AI capabilities', '5', '1', '4', 'Reduces manual account coding time and coding error rate for AP invoices', 'Activate Intelligent Account Combination Defaulting in Oracle Fusion Payables; finance team reviews and approves defaulting rules.', 'Built-in Oracle Payables AI feature; automates account code prediction', '1) Restrict first use to read-only analysis, recommendations, or dry-run output.\n2) Validate in non-production and document approval gates before operational use.\n3) Convert proven outputs into governed templates/runbooks rather than free-form prompting.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-012', 'Supplier Instruction Knowledge Agent', 'RAG-powered AI agent that ingests supplier user guides and instruction documents, enabling business users to query supplier processes and procurement instructions through a conversational interface.', 'ERP Solutions', 'Development', 'Custom AI Agent', 'Procurement Knowledge', 'ChatGPT, Azure OpenAI', '6', '2', '4', 'Reduces supplier instruction query time and improves procurement process self-service', 'Define document scope; build RAG pipeline with document refresh schedule; business users query via chat; ERP owner reviews response accuracy monthly.', 'Custom RAG solution; requires document ingestion pipeline and governance', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ERP-AI-002', 'AI-Powered Oracle Fusion DM Validation and Generation HDL', 'An AI-powered use case for validating and processing HR data for Oracle Fusion HCM using HCM Data Loader (HDL) format. The solution leverages AI platforms (Claude or ChatGPT) to automatically cleanse, validate, and transform Excel/CSV data into properly formatted HDL files ready for import into Oracle Fusion.', 'ERP Solutions', 'Development', 'Data Processing', 'Data Migration', 'ChatGPT, Claude', '10', '3', '7', '•	Reduces data preparation time by 80-90%\n•	Eliminates manual errors in HDL file creation\n•	Ensures data quality and compliance with Oracle standards\n•	Provides transparent validation and error reporting\n•	Supports complex multi-object HDL scenarios', 'Use AI on approved internal artifacts, then validate outputs by lead engineers or analysts before delivery.', 'Reusable across multiple projects with minimal setup', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ERP-AI-003', 'SQL Query Generation via Claude AI', 'Use AI to generate SQL queries for ERP reports using schema and business inputs', 'ERP Solutions', 'Development / Support', 'Productivity Enhancement', 'Reporting Automation', 'Claude AI', '6', '1', '5', '- 75–87% time reduction\n- 90% error reduction\n- Faster delivery\n- Reduce dependency on experts\n- Improve data accuracy', '- Provide schema and table structure\n- Define business requirement clearly\n- Validate output before production\n- Store reusable queries', '- AI enables self-service reporting\n- Scalable across teams\n- Reduces workload\n- Supports faster decision making', '1) Start with one approved artifact set and a fixed output template.\n2) Pilot on a single project/workshop and measure time saved plus review corrections.\n3) Promote validated prompt packs and review checklist into the BA knowledge base.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Hassan Mantawy', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ERP-AI-004', 'AI-Augmented Oracle HCM Cloud Implementation Strategy', 'This proposal introduces a Knowledge-Based Agent System that serves as an institutional expert across all Oracle HCM implementation phases. The system comprises two foundational components:\n•	Centralized Knowledge Repository: A structured database containing historical project documentation (BRDs, fit-gap analyses, meeting minutes, MoSCoW prioritizations, future-state process maps, solution designs, technical specifications) and verified government policies from official sources (labor regulations, social insurance requirements, taxation rules, localization standards). Documents are tagged with metadata including industry vertical, public/private sector classification, implemented modules, and country-specific requirements.\n•	AI Agent Layer: A generative AI system trained on the knowledge repository, capable of retrieval-augmented generation (RAG), natural language interaction, document drafting, policy analysis, and predictive risk assessment. The agent operates through defined workflows aligned with implementation methodology phases.', 'ERP Solutions', 'Entire Project Phases', 'Productivity Enhancement', NULL, 'Vector Database, LLM, RAG tools', '12', '5', '7', '•	Time saved (estimated): 40% faster project delivery.\n•	Effort reduced: 30-50% reduction in documentation workload.\n•	Quality improvement: 40% fewer defects, 60% improved policy compliance, 35% better requirement completeness.\n•	Reduction in errors or rework.', 'The system leverages vector database for semantic similarity matching. Documents undergo preprocessing: text extraction, embedding generation using OpenAI or Oracle Cohere models, and metadata tagging.\nThe AI agent utilizes a large language model (Oracle Generative AI, Azure OpenAI GPT-4, or AWS) configured for retrieval-augmented generation. When queried, the system retrieves top relevant document chunks, injects them as context into the prompt, and generates responses grounded in organizational knowledge.', 'Faster kickoff, reduced policy research effort, improved proposal quality.\n\nFaster fit-gap completion, better solution consistency, improved requirement coverage.\n\nFaster configuration setup, fewer errors, quicker data mapping.\n\nFaster test preparation, broader coverage, quicker defect resolution, fewer post-go-live issues.\n\nFaster training preparation, higher adoption, reduced support tickets.\n\nFaster issue resolution, more optimization opportunities, increased managed services value.', '1) Start with one approved artifact set and a fixed output template.\n2) Pilot on a single project/workshop and measure time saved plus review corrections.\n3) Promote validated prompt packs and review checklist into the BA knowledge base.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Hossam Farag', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ORACLE-AI-013', 'Supplier Aging Report Analysis Agent', 'Custom AI agent that analyzes supplier aging reports and procurement documents, providing context-aware insights on outstanding balances, payment trends, and supplier risk indicators.', 'ERP Solutions', 'Development', 'Custom AI Agent', 'Financial Analysis', 'ChatGPT, Azure OpenAI', '6', '2', '4', 'Reduces aging report analysis time and improves supplier risk visibility', 'Clarify document scope; obtain legal/compliance clearance for document ingestion; build RAG pipeline with data residency controls.', 'Custom RAG solution; requires compliance clearance and document governance', '1) Pilot on a representative sample dataset with known rules and target structure.\n2) Measure effort reduction, mapping accuracy, and defect/rework rate.\n3) Promote reusable mappings, prompts, and validation checklist after SME sign-off.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Reham Ibrahim', 'Planned', NULL, true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('BFSI-GRC-01', 'SQL Code Optimization', 'using AI to optimize the SQL queries to remove full table scan.\nIn some of our PL/SQL code (SQL Queries), we are getting Full table scan. So in all such cases if the table is very huge, then the query performance is getting very slow and the execution time is very high which results in poor performance. So we need to optimize the code for to achieve better performance', 'GRC', 'Development', 'Backend', 'Development Acceleration and optimization', 'Toad for Oracle, Copilot for taking help', '5 Hours if performed manually', '1 hour', 'It will help us reduce the development time by at least 30%', '80% reduction in time', '1. Identifying the query that needs to optimized using the Execution plan in Toad or SQL Developer.\n2. Clearly defining the joining conditions of different tables being used in the query.\n3. Building indexes on the different columns being used on the joinging conditions.\n4. taking help of AI to optimize the code', 'Getting Optimized SQL Queries without full table scan', '1) Pilot on one application/API scope with approved requirements and expected results.\n2) Track coverage improvement, preparation effort, and escaped defects.\n3) Reuse validated scenarios/prompts inside the QE repository.', 'Accepted Idea', 'Accepted – Ready for Implementation', 'Well-formed use case with clear business value, valid AI role, and enough delivery context to move into controlled implementation with SME review and quality gates.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Mohamed Essam', 'In Progress', '2 Developers', false, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('CES-AI-DOC-001', 'Document Generation', 'AI assistance in analyzing BRDs helping in efficient generation for HLD and LLD structured Diagrams and business models to optimise Technical Leads and designers time', 'CES', 'Analysis', 'Requirements Analysis', NULL, 'Eraser AI & Chatgpt', '132', '84', '5', 'Reduces documentation effort and improves consistency of HLD/LLD artifacts', 'Use past project documents and templates as grounding input before generating HLD/LLD drafts; Technical Lead reviews before delivery.', 'Reusable across multiple projects with minimal setup; standardizes documentation quality', '1) Start with one approved artifact set and a fixed output template.\n2) Pilot on a single project/workshop and measure time saved plus review corrections.\n3) Promote validated prompt packs and review checklist into the BA knowledge base.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Norah Al Wabel', NULL, NULL, false, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('CES-AI-DEV-001', 'Code optimization', 'Enhancing C# Code to achieve more generic/reusable and better performing services/processes', 'CES', 'Development', 'Backend', NULL, 'GitHub Copilot, Claude Code', '4', '2', '2', 'Improves code quality, reusability, and performance of C# services', 'Use AI on approved internal code artifacts; validate optimized code through code review and automated tests before deployment.', 'High value for recurring development optimization activities', '1) Pilot on one HLD/LLD or process-design package with architect-approved patterns.\n2) Measure draft-preparation time, correction rate, and review-cycle reduction.\n3) Reuse only approved templates, diagram rules, and prompt packs.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Norah Al Wabel', NULL, NULL, false, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-BA-01', 'Meeting Minutes (MoM) Auto-Drafting', 'AI generates structured meeting minutes from recorded meeting transcripts, including attendees, decisions, action items, owners, and due dates, significantly reducing MoM preparation time.', 'EPS', 'Analysis', 'Requirements Management', 'Meeting Documentation', 'Microsoft 365 Copilot, ChatGPT', '2', '0.5', '1.5', 'Reduces MoM preparation time and improves consistency of meeting documentation', 'Capture or export meeting transcript; prompt AI to draft structured minutes; reviewer validates wording and confidentiality before sending.', 'Reusable across multiple projects with minimal setup', 'Capture or export meeting transcript, then prompt AI to draft structured minutes with attendees, decisions, actions, owners, and due dates. Reviewer validates wording and confidentiality before sending.', 'Accepted Idea', 'Accepted – Ready for Implementation', 'Well-formed use case with clear business value, valid AI role, and enough delivery context to move into controlled implementation with SME review and quality gates.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'In Progress', '1', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-BA-03', 'Reverse Engineering Logic from Code', 'During Requirement gathering, Shabbir & ALI from ANB side shared the SQL stored procedures code files with us to get details about processing logic in TAPS for enrichment,validations, encryption as well as for narratives building.  I used ChatGpt to reverse engineer the logic. Using this only we could be able to complete our requirement gathering.', 'EPS', 'Analysis', 'Requirements Management', 'Requirements Discovery', 'ChatGPT, Claude', '8', '3', '5', 'Accelerates requirements gathering from legacy code and reduces dependency on original developers', 'Provide sanitized stored procedures or code files; AI extracts logic, validations, and business rules; BA validates interpretation with SMEs.', 'High value for recurring SDLC activities involving legacy systems', 'Provide sanitized stored procedures or code files, ask AI to extract logic, validations, rules, and narrative flows, then BA validates the interpretation with SMEs before using it in requirements baselines.', 'Accepted Idea', 'Accepted – Ready for Implementation', 'Well-formed use case with clear business value, valid AI role, and enough delivery context to move into controlled implementation with SME review and quality gates.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'In Progress', '1', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-BA-04', 'SWIFT Message Reference and Sample Generation', 'AI provides reference information on SWIFT message types, general processing flows, and sample data structures when official SWIFT documentation is not accessible, supporting requirements analysis and business discussions.', 'EPS', 'Analysis', 'Requirements Management', 'Domain Knowledge Research', 'Microsoft 365 Copilot, ChatGPT', '4', '1', '3', 'Accelerates SWIFT-related requirements research and reduces dependency on documentation access', 'Use AI for preliminary orientation and draft sample messages; validate all details against official SWIFT documentation or SME confirmation.', 'Useful research accelerator; must verify against official sources', 'Use AI only for preliminary orientation or draft sample messages. Validate all message structures, processing details, and reference data against official SWIFT documentation or SME confirmation before use.', 'Accepted Idea', 'Accepted – Ready for Implementation', 'Well-formed use case with clear business value, valid AI role, and enough delivery context to move into controlled implementation with SME review and quality gates.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'In Progress', '1', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-BA-05', 'Test Data Generation and Preparation', 'AI generates realistic test data sets based on business scenarios, field constraints, and validation rules, reducing manual test data preparation effort and improving coverage.', 'EPS', 'Testing', 'Quality Assurance', 'Test Data Preparation', 'ChatGPT, Claude', '6', '2', '4', 'Reduces test data preparation effort and improves scenario coverage', 'Define target scenario types, required fields, validation rules, and masking constraints; AI drafts test data sets; tester validates realism and coverage.', 'Best suited for pilot-to-scale adoption with clear data constraints', 'Define target scenario types, required fields, validation rules, and masking constraints. Use AI to draft representative test data sets, then tester validates realism and coverage before execution.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-QA-01', 'Test Case Generation from User Stories', 'AI derives comprehensive test cases including positive, negative, and boundary scenarios from approved user stories and acceptance criteria.', 'EPS', 'Testing', 'Test Automation', 'Test Case Generation', 'ChatGPT, Claude', '6', '2', '4', 'Speeds up test preparation and improves defect discovery through broader coverage', 'Provide approved user stories and acceptance criteria; AI generates test cases; QA reviews and enriches before adding to test repository.', 'Proven GenAI pattern; story quality directly affects output quality', 'Provide approved user stories and acceptance criteria, generate positive/negative/boundary test cases with AI, then QA reviews and enriches them before adding to the test repository.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-QA-02', 'User Story Enhancement for Tester Readability', 'AI enhances story descriptions and acceptance criteria into tester-readable format with explicit scenarios and assumptions, while preserving intent and traceability.', 'EPS', 'Analysis / Testing', 'Requirements Management', 'Requirements Readability', 'ChatGPT, Claude', '3', '1', '2', 'Improves requirement clarity and reduces tester interpretation errors', 'Feed original story and acceptance criteria to AI; request tester-oriented reformulation; QA or BA validates against source story.', 'Reusable across multiple projects with minimal setup', 'Feed the original story and acceptance criteria to AI, ask for tester-oriented reformulation with explicit scenarios and assumptions, then QA or BA validates against the source story before use.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-BA-06', 'AI-Assisted User Guide Drafting', 'AI generates structured user guide content from scripts, process steps, and system descriptions, producing professional documentation drafts for review and refinement.', 'EPS', 'Documentation', 'Documentation', 'User Guide Generation', 'Microsoft 365 Copilot, ChatGPT', '6', '2', '4', 'Reduces documentation effort and improves consistency of user guides', 'Provide scripts, process steps, screenshots, and approved user-guide template; AI drafts structured content; SME or BA reviews for correctness.', 'Best suited for pilot-to-scale adoption with standard templates', 'Provide scripts, process steps, screenshots, and the approved user-guide template. Use AI to draft structured paragraphs and candidate visuals, then SME or BA reviews for correctness and usability.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-DEV-01', 'Issue Resolution and Code Fix Acceleration', 'AI-assisted analysis and resolution of development tickets including SQL execution issues, code performance bottlenecks, and runtime errors. AI suggests root causes and optimized fixes to accelerate ticket closure.', 'EPS', 'Development', 'Development Acceleration', 'Issue Resolution', 'GitHub Copilot, Claude Code', '4', '2', '2', 'Accelerates ticket resolution and improves code quality', 'Capture error context and relevant code; AI suggests root cause and optimized fix; developer validates before applying.', 'High value for recurring development support activities', '1) Pilot on one application/API scope with approved requirements and expected results.\n2) Track coverage improvement, preparation effort, and escaped defects.\n3) Reuse validated scenarios/prompts inside the QE repository.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-DEV-02', 'Pull Request Drafting and Code Review Assistance', 'AI assists in drafting pull request descriptions, summarizing code changes, and performing preliminary code review to identify potential issues before human review.', 'EPS', 'Development', 'Development Acceleration', 'Code Review', 'GitHub Copilot, Claude Code', '4', '2', '2', 'Accelerates code review process and improves PR quality and consistency', 'Use AI to generate PR description from diff; AI performs preliminary review; lead engineer validates before merge.', 'Reusable across all development projects with minimal setup', '1) Pilot on a bounded engineering task in a controlled repository.\n2) Enforce human review, unit/integration tests, and security checks on all AI-generated output.\n3) Package the winning prompt/context pattern as a reusable accelerator.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPS-DEV-04', 'AI-Augmented Development Process Enhancement', 'Leverage AI tools to accelerate development workflows including code scaffolding, API integration research, technical documentation, and internal POC development for emerging technologies.', 'EPS', 'Development', 'Development Acceleration', 'Process Optimization', 'GitHub Copilot, Claude Code, ChatGPT', '6', '2', '4', 'Accelerates development workflows and reduces effort for routine engineering tasks', 'Use AI for code scaffolding, API research, and internal POCs; validate outputs through practice leads before delivery.', 'Umbrella use case covering development workflow improvements; best suited for project-level pilots', '1) Pilot on a bounded engineering task in a controlled repository.\n2) Enforce human review, unit/integration tests, and security checks on all AI-generated output.\n3) Package the winning prompt/context pattern as a reusable accelerator.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Yousef Milhem', 'Planned', '0', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-118', 'application development and configuration', 'Alfresco  ECM serach capabilites', 'EPCS', 'Development / support', 'Development Acceleration', 'Code generation', 'GitHub Copilot', NULL, NULL, '24 working hours', 'Faser to finalize customer CR', 'add and configure HTTP-to-HTTPS proxy to Alfresco Kubernetes cluster to keep Elastisearch secured', NULL, '1) Pilot on a bounded engineering task in a controlled repository.\n2) Enforce human review, unit/integration tests, and security checks on all AI-generated output.\n3) Package the winning prompt/context pattern as a reusable accelerator.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed AlSareti', 'Implemented', NULL, false, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('EPCS-AI-119', 'application development', 'Alfresco ECM front-end application', 'EPCS', 'Development', 'Development Acceleration', 'Code modernization', 'GitHub Copilot', NULL, NULL, '48 working hours', 'enhance internal web applications development', 'update Alfresco workspace front-end application (Angular) to allow search by metadata', NULL, '1) Pilot on a bounded engineering task in a controlled repository.\n2) Enforce human review, unit/integration tests, and security checks on all AI-generated output.\n3) Package the winning prompt/context pattern as a reusable accelerator.', 'Accepted Idea', 'Accepted – Proven with Adoption Evidence', 'Strong and practical use case with clear AI relevance and evidence of real usage or measurable adoption indicators. Suitable to institutionalize and extend under governed patterns.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Ahmed AlSareti', 'Implemented', NULL, false, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ERP-AI-005', 'AI-Powered ERP Reporting & Documentation Automation', 'End-to-end AI-assisted workflow for ERP reporting tasks including requirement analysis, SQL development, RTF template generation, TDD creation, and knowledge management to improve productivity and reduce manual effort.', 'ERP Solutions', 'Design, Development, Testing, Documentation', 'Productivity Enhancement', 'ERP Reporting Automation & Knowledge Management', 'ChatGPT, Claude', '3 Days per task', 'Reduced by 15%–20% (2.4–2.55 Days)', '4.8 to 7.2 hours per task', 'Faster delivery, reduced manual effort, fewer SQL errors, improved documentation quality, enhanced knowledge reuse, reduced dependency on individuals', 'Use AI tools (ChatGPT, Claude) across lifecycle: requirement capture, SQL generation, RTF creation, and TDD generation. Maintain structured knowledge repository. Standardize prompts and outputs.', 'Transition from task-based AI usage to full lifecycle AI integration. Build long-term AI-powered knowledge repository for scalable productivity gains (target 30%+).', '1) Start with one approved artifact set and a fixed output template.\n2) Pilot on a single project/workshop and measure time saved plus review corrections.\n3) Promote validated prompt packs and review checklist into the BA knowledge base.', 'Accepted Idea', 'Accepted – Ready for Implementation', 'Well-formed use case with clear business value, valid AI role, and enough delivery context to move into controlled implementation with SME review and quality gates.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Doaa Mostafa', 'In Progress (Individual Usage Phase)', 'Currently Individual Level (Expected to scale to Team Level)', true, true, true) ON CONFLICT (asset_id) DO NOTHING;
INSERT INTO use_cases (asset_id, name, description, practice, sdlc_phase, category, subcategory, ai_tools, efforts_without_ai, efforts_with_ai, hours_saved_per_impl, business_benefits, implementation_guidelines, strategic_takeaways, suggestion_how_to_apply, validation_feedback, validation_detail, validation_notes, reality_doability, owner_spoc, current_status, no_of_adoptions, selected_use_case, is_approved_reference, is_active) VALUES ('ERP-AI-006', 'AI-Driven HDL Data Migration Automation', 'AI-powered solution to automate data cleansing, validation, mapping, error prediction, and HDL file generation for Oracle HCM data migration, reducing manual effort and improving upload success rate.', 'ERP Solutions', 'Data Preparation, Development, Testing, Deployment', 'Productivity Enhancement', 'Data Migration Automation (HCM / HDL)', 'ChatGPT, Claude', 'Several Days (depending on data volume)', 'Reduced to Few Hours', '16 to 24 hours per migration cycle', 'Faster migration cycles, improved data accuracy, reduced upload failures, minimized rework, lower dependency on multiple consultants, improved project delivery timelines', 'Use AI tools (ChatGPT, Claude) for data validation, mapping, and HDL generation. Build reusable templates for common objects. Integrate AI checks before HDL upload. Maintain structured validation rules.', 'AI can transform data migration from manual iterative process to automated intelligent workflow. Strong potential for reuse across all HCM projects.', '1) Pilot on one application/API scope with approved requirements and expected results.\n2) Track coverage improvement, preparation effort, and escaped defects.\n3) Reuse validated scenarios/prompts inside the QE repository.', 'Accepted Idea', 'Accepted – Ready for Pilot', 'Clear and feasible AI use case with meaningful delivery value. Best advanced through a controlled pilot to validate effort saving, quality improvement, and review effort before broader rollout.', 'High feasibility. The use case has a clear business problem, a valid AI role, and a workable delivery path if grounded on approved inputs and reviewed by the responsible SME/lead before release.', 'Doaa Mostafa', 'Planned', 'Currently Idea Phase (Planned for Implementation)', true, true, true) ON CONFLICT (asset_id) DO NOTHING;